func TestNovelSavingsBehavior(t *testing.T) {
	receipts := []costcoReceipt{
		{InstantSavings: 5.00, CouponArray: []costcoCoupon{{Amount: 3.00}, {Amount: -2.00}}},
		{InstantSavings: 1.50, CouponArray: nil},
	}

	t.Run("totals instant savings and absolute coupon amounts", func(t *testing.T) {
		v := computeSavings(receipts, "2025-01-01", "2025-12-31")
		if v.ReceiptCount != 2 {
			t.Fatalf("ReceiptCount = %d, want 2", v.ReceiptCount)
		}
		if v.InstantSavings != 6.50 {
			t.Fatalf("InstantSavings = %v, want 6.50", v.InstantSavings)
		}
		if v.CouponSavings != 5.00 {
			t.Fatalf("CouponSavings = %v, want 5.00 (abs of 3 and -2)", v.CouponSavings)
		}
		if v.TotalSavings != 11.50 {
			t.Fatalf("TotalSavings = %v, want 11.50", v.TotalSavings)
		}
	})

	t.Run("empty input yields zero savings, not phantom values", func(t *testing.T) {
		v := computeSavings(nil, "a", "b")
		if v.TotalSavings != 0 || v.ReceiptCount != 0 {
			t.Fatalf("empty savings = %+v, want all zero", v)
		}
	})
}
